function clamp(t,n,e){return Math.min(Math.max(t,n),e)}const cosh=function(){let t;return t="cosh"in Math?Math.cosh:function(t){t=Math.exp(t);return(t+1/t)/2}}(),log2=function(){let t;return t="log2"in Math?Math.log2:function(t){return Math.log(t)*Math.LOG2E}}();function squaredSegmentDistance(t,n,e,r,o,a){var u,i=o-e,c=a-r;return 0==i&&0==c||(1<(u=((t-e)*i+(n-r)*c)/(i*i+c*c))?(e=o,r=a):0<u&&(e+=i*u,r+=c*u)),squaredDistance(t,n,e,r)}function squaredDistance(t,n,e,r){e-=t,t=r-n;return e*e+t*t}function solveLinearSystem(o){var a=o.length;for(let r=0;r<a;r++){let n=r,e=Math.abs(o[r][r]);for(let t=r+1;t<a;t++){var u=Math.abs(o[t][r]);u>e&&(e=u,n=t)}if(0===e)return null;var t=o[n];o[n]=o[r],o[r]=t;for(let n=r+1;n<a;n++){var i=-o[n][r]/o[r][r];for(let t=r;t<a+1;t++)r==t?o[n][t]=0:o[n][t]+=i*o[r][t]}}const e=new Array(a);for(let n=a-1;0<=n;n--){e[n]=o[n][a]/o[n][n];for(let t=n-1;0<=t;t--)o[t][a]-=o[t][n]*e[n]}return e}function toDegrees(t){return 180*t/Math.PI}function toRadians(t){return t*Math.PI/180}function modulo(t,n){t%=n;return t*n<0?t+n:t}function lerp(t,n,e){return t+e*(n-t)}function toFixed(t,n){n=Math.pow(10,n);return Math.round(t*n)/n}function round(t,n){return Math.round(toFixed(t,n))}function floor(t,n){return Math.floor(toFixed(t,n))}function ceil(t,n){return Math.ceil(toFixed(t,n))}export{clamp,cosh,log2,squaredSegmentDistance,squaredDistance,solveLinearSystem,toDegrees,toRadians,modulo,lerp,toFixed,round,floor,ceil};